import React, { useState } from 'react';
import styled, { keyframes } from 'styled-components';
import { 
  CreditCard, 
  Database, 
  Grid, 
  Bot, 
  CheckCircle, 
  AlertCircle, 
  Plus, 
  Settings,
  Zap,
  Link,
  Shield,
  Key,
  RefreshCw,
  Trash2,
  Edit3,
  Eye,
  EyeOff
} from 'lucide-react';

const pulse = keyframes`
  0%, 100% { opacity: 1; }
  50% { opacity: 0.5; }
`;

const slideIn = keyframes`
  from { opacity: 0; transform: translateY(20px); }
  to { opacity: 1; transform: translateY(0); }
`;

const Container = styled.div`
  padding: 2rem;
  background: linear-gradient(135deg, #f0f4f8 0%, #e6f7ff 100%);
  min-height: 100vh;
`;

const Header = styled.div`
  margin-bottom: 2rem;
`;

const Title = styled.h1`
  font-size: 2rem;
  font-weight: 700;
  color: #1e293b;
  margin-bottom: 0.5rem;
`;

const Subtitle = styled.p`
  color: #64748b;
  font-size: 1.1rem;
`;

const IntegrationsGrid = styled.div`
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(350px, 1fr));
  gap: 1.5rem;
  margin-bottom: 2rem;
`;

const IntegrationCard = styled.div`
  background: white;
  border-radius: 1.25rem;
  padding: 1.5rem;
  box-shadow: 0 8px 30px rgba(0, 0, 0, 0.08);
  border: 1px solid #e2e8f0;
  transition: all 0.3s ease;
  
  &:hover {
    transform: translateY(-5px);
    box-shadow: 0 12px 40px rgba(0, 0, 0, 0.12);
  }
`;

const IntegrationHeader = styled.div`
  display: flex;
  align-items: center;
  gap: 1rem;
  margin-bottom: 1.5rem;
`;

const IntegrationIcon = styled.div`
  width: 3.5rem;
  height: 3.5rem;
  border-radius: 1rem;
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  display: flex;
  align-items: center;
  justify-content: center;
  color: white;
`;

const IntegrationInfo = styled.div`
  flex: 1;
`;

const IntegrationName = styled.h3`
  font-size: 1.25rem;
  font-weight: 600;
  color: #1e293b;
  margin: 0 0 0.25rem 0;
`;

const IntegrationDescription = styled.p`
  color: #64748b;
  font-size: 0.9rem;
  margin: 0;
`;

const IntegrationStatus = styled.div`
  display: flex;
  align-items: center;
  gap: 0.5rem;
  font-size: 0.9rem;
  font-weight: 500;
  
  &.connected {
    color: #10b981;
  }
  
  &.disconnected {
    color: #ef4444;
  }
`;

const IntegrationActions = styled.div`
  display: flex;
  gap: 0.75rem;
  margin-top: 1.5rem;
  padding-top: 1.5rem;
  border-top: 1px solid #f1f5f9;
`;

const ActionButton = styled.button`
  flex: 1;
  background: #f1f5f9;
  border: none;
  padding: 0.75rem;
  border-radius: 0.75rem;
  font-size: 0.9rem;
  font-weight: 500;
  cursor: pointer;
  color: #1e293b;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 0.5rem;
  transition: all 0.2s ease;
  
  &:hover {
    background: #e2e8f0;
  }
  
  &.primary {
    background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
    color: white;
    
    &:hover {
      opacity: 0.9;
    }
  }
  
  &.danger {
    background: #fee2e2;
    color: #ef4444;
    
    &:hover {
      background: #fecaca;
    }
  }
`;

const FormSection = styled.div`
  background: white;
  border-radius: 1.25rem;
  padding: 2rem;
  box-shadow: 0 8px 30px rgba(0, 0, 0, 0.08);
  border: 1px solid #e2e8f0;
  margin-bottom: 2rem;
  animation: ${slideIn} 0.5s ease-out;
`;

const SectionTitle = styled.h2`
  font-size: 1.5rem;
  font-weight: 600;
  color: #1e293b;
  margin-bottom: 1.5rem;
  display: flex;
  align-items: center;
  gap: 0.75rem;
`;

const Form = styled.form`
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 1.5rem;
  
  @media (max-width: 768px) {
    grid-template-columns: 1fr;
  }
`;

const FormGroup = styled.div`
  grid-column: ${props => props.fullWidth ? '1 / -1' : 'auto'};
`;

const Label = styled.label`
  display: block;
  font-size: 0.9rem;
  font-weight: 500;
  color: #1e293b;
  margin-bottom: 0.5rem;
`;

const Input = styled.input`
  width: 100%;
  padding: 0.75rem 1rem;
  border: 1px solid #e2e8f0;
  border-radius: 0.75rem;
  font-size: 1rem;
  transition: all 0.2s ease;
  
  &:focus {
    outline: none;
    border-color: #667eea;
    box-shadow: 0 0 0 3px rgba(102, 126, 234, 0.1);
  }
`;

const InputWithIcon = styled.div`
  position: relative;
  
  input {
    padding-right: 3rem;
  }
  
  svg {
    position: absolute;
    right: 1rem;
    top: 50%;
    transform: translateY(-50%);
    color: #94a3b8;
    cursor: pointer;
  }
`;

const SubmitButton = styled.button`
  background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
  color: white;
  border: none;
  padding: 1rem 2rem;
  border-radius: 0.75rem;
  font-size: 1rem;
  font-weight: 600;
  cursor: pointer;
  transition: all 0.3s ease;
  box-shadow: 0 4px 15px rgba(102, 126, 234, 0.3);
  grid-column: 1 / -1;
  width: 100%;
  
  &:hover {
    transform: translateY(-2px);
    box-shadow: 0 6px 20px rgba(102, 126, 234, 0.4);
  }
  
  &:disabled {
    opacity: 0.7;
    cursor: not-allowed;
    transform: none;
  }
`;

const Tabs = styled.div`
  display: flex;
  gap: 0.5rem;
  margin-bottom: 2rem;
  border-bottom: 1px solid #e2e8f0;
  padding-bottom: 1rem;
`;

const Tab = styled.button`
  background: ${props => props.active ? '#667eea' : 'transparent'};
  color: ${props => props.active ? 'white' : '#64748b'};
  border: none;
  padding: 0.75rem 1.5rem;
  border-radius: 2rem;
  font-size: 0.9rem;
  font-weight: 500;
  cursor: pointer;
  transition: all 0.2s ease;
  
  &:hover {
    background: ${props => props.active ? '#667eea' : '#f1f5f9'};
  }
`;

function Integrations() {
  const [activeTab, setActiveTab] = useState('all');
  const [showApiKey, setShowApiKey] = useState(false);
  const [formData, setFormData] = useState({
    stripeSecretKey: '',
    googleClientId: '',
    googleClientSecret: '',
    deepseekApiKey: ''
  });
  
  const integrations = [
    {
      id: 'stripe',
      name: 'Stripe Payments',
      description: 'Accept payments with Stripe',
      icon: <CreditCard size={24} />,
      connected: true
    },
    {
      id: 'google-drive',
      name: 'Google Drive',
      description: 'Access and manage Google Drive files',
      icon: <Database size={24} />,
      connected: false
    },
    {
      id: 'google-sheets',
      name: 'Google Sheets',
      description: 'Read and write Google Sheets data',
      icon: <Grid size={24} />,
      connected: true
    },
    {
      id: 'deepseek',
      name: 'DeepSeek AI',
      description: 'Generate code with DeepSeek AI',
      icon: <Bot size={24} />,
      connected: false
    }
  ];
  
  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };
  
  const handleSubmit = (e) => {
    e.preventDefault();
    // Handle form submission
    console.log('Form submitted:', formData);
  };
  
  return (
    <Container>
      <Header>
        <Title>Integrations</Title>
        <Subtitle>Connect your favorite tools and services to enhance your workflow</Subtitle>
      </Header>
      
      <Tabs>
        <Tab active={activeTab === 'all'} onClick={() => setActiveTab('all')}>All Integrations</Tab>
        <Tab active={activeTab === 'connected'} onClick={() => setActiveTab('connected')}>Connected</Tab>
        <Tab active={activeTab === 'available'} onClick={() => setActiveTab('available')}>Available</Tab>
      </Tabs>
      
      <IntegrationsGrid>
        {integrations.map((integration) => (
          <IntegrationCard key={integration.id}>
            <IntegrationHeader>
              <IntegrationIcon>
                {integration.icon}
              </IntegrationIcon>
              <IntegrationInfo>
                <IntegrationName>{integration.name}</IntegrationName>
                <IntegrationDescription>{integration.description}</IntegrationDescription>
              </IntegrationInfo>
              <IntegrationStatus className={integration.connected ? 'connected' : 'disconnected'}>
                {integration.connected ? <CheckCircle size={16} /> : <AlertCircle size={16} />}
                {integration.connected ? 'Connected' : 'Not Connected'}
              </IntegrationStatus>
            </IntegrationHeader>
            
            <IntegrationActions>
              {integration.connected ? (
                <>
                  <ActionButton>
                    <Settings size={16} />
                    Settings
                  </ActionButton>
                  <ActionButton className="danger">
                    <Trash2 size={16} />
                    Disconnect
                  </ActionButton>
                </>
              ) : (
                <>
                  <ActionButton className="primary">
                    <Link size={16} />
                    Connect
                  </ActionButton>
                  <ActionButton>
                    <Eye size={16} />
                    Preview
                  </ActionButton>
                </>
              )}
            </IntegrationActions>
          </IntegrationCard>
        ))}
      </IntegrationsGrid>
      
      <FormSection>
        <SectionTitle>
          <Settings size={24} />
          API Configuration
        </SectionTitle>
        
        <Form onSubmit={handleSubmit}>
          <FormGroup>
            <Label>Stripe Secret Key</Label>
            <InputWithIcon>
              <Input
                type={showApiKey ? "text" : "password"}
                name="stripeSecretKey"
                value={formData.stripeSecretKey}
                onChange={handleInputChange}
                placeholder="sk_live_..."
              />
              <button type="button" onClick={() => setShowApiKey(!showApiKey)}>
                {showApiKey ? <EyeOff size={16} /> : <Eye size={16} />}
              </button>
            </InputWithIcon>
          </FormGroup>
          
          <FormGroup>
            <Label>Google Client ID</Label>
            <Input
              type="text"
              name="googleClientId"
              value={formData.googleClientId}
              onChange={handleInputChange}
              placeholder="Your Google Client ID"
            />
          </FormGroup>
          
          <FormGroup>
            <Label>Google Client Secret</Label>
            <Input
              type="password"
              name="googleClientSecret"
              value={formData.googleClientSecret}
              onChange={handleInputChange}
              placeholder="Your Google Client Secret"
            />
          </FormGroup>
          
          <FormGroup>
            <Label>DeepSeek API Key</Label>
            <Input
              type="password"
              name="deepseekApiKey"
              value={formData.deepseekApiKey}
              onChange={handleInputChange}
              placeholder="Your DeepSeek API Key"
            />
          </FormGroup>
          
          <SubmitButton type="submit">
            <Zap size={16} />
            Save Configuration
          </SubmitButton>
        </Form>
      </FormSection>
    </Container>
  );
}

export default Integrations;
